package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Method;

class ExtendedBufferedReaderTest {

    ExtendedBufferedReader extendedBufferedReader;
    Reader mockReader;

    @BeforeEach
    void setUp() {
        mockReader = mock(Reader.class);
        extendedBufferedReader = new ExtendedBufferedReader(mockReader) {
            // Override read() to call super.read() on the mockReader
            @Override
            public int read() throws IOException {
                return super.read();
            }
        };
    }

    @Test
    void testReadReturnsCharNotNewline() throws IOException {
        ExtendedBufferedReader spyReader = spy(extendedBufferedReader);
        // Mock super.read() to return 'a' (not newline)
        doReturn((int) 'a').when(spyReader).read();
        // To avoid infinite recursion, call the real super.read() using reflection:
        // But here we mock read() itself to return 'a' so call spyReader.read() will return 'a'
        // We want to test ExtendedBufferedReader.read(), but spyReader.read() is overridden by doReturn.
        // So, instead, we test the original method by calling it via reflection.

        // We need to call the real read() method on ExtendedBufferedReader which calls super.read()
        // but super.read() calls Reader.read() which we have mocked.

        // Instead of mocking read(), mock the underlying Reader's read() for super.read() call:
        when(mockReader.read()).thenReturn((int) 'a');

        int result = spyReader.read();

        assertEquals('a', result);
        assertEquals('a', getLastChar(spyReader));
        assertEquals(0, getLineCounter(spyReader));
    }

    @Test
    void testReadReturnsNewlineIncrementsLineCounter() throws IOException {
        when(mockReader.read()).thenReturn((int) '\n');

        int result = extendedBufferedReader.read();

        assertEquals('\n', result);
        assertEquals('\n', getLastChar(extendedBufferedReader));
        assertEquals(1, getLineCounter(extendedBufferedReader));
    }

    @Test
    void testReadReturnsEndOfStream() throws IOException {
        when(mockReader.read()).thenReturn(ExtendedBufferedReader.END_OF_STREAM);

        int result = extendedBufferedReader.read();

        assertEquals(ExtendedBufferedReader.END_OF_STREAM, result);
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, getLastChar(extendedBufferedReader));
        assertEquals(0, getLineCounter(extendedBufferedReader));
    }

    private int getLastChar(ExtendedBufferedReader reader) {
        try {
            var field = ExtendedBufferedReader.class.getDeclaredField("lastChar");
            field.setAccessible(true);
            return field.getInt(reader);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    private int getLineCounter(ExtendedBufferedReader reader) {
        try {
            var field = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
            field.setAccessible(true);
            return field.getInt(reader);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}
